#include <stdio.h>

int prime[1005000];
int primeList[1005000];

void init() {
    int i, cnt = 0, j;
    prime[2] = 1;
    primeList[cnt++] = 2;
    for(i = 3; i < 1005000; i += 2) {
        for(j = 0; j < cnt; j++) {
            if(i % primeList[j] == 0) break;
            if((1ll * primeList[j]) * primeList[j] > i) break;
        }
        if(j == cnt || i % primeList[j] != 0) {
            primeList[cnt++] = i;
            prime[i] = 1;
        }
    }
}

int good(int a, int b, int len, int need) {
    int start, cur = 0;
    for(start = a; start <= b; start++) {
        cur += prime[start];
        if(start - a + 1 == len)
            if(cur < need) return 0;
        if(start - len >= a) {
            cur -= prime[start - len];
            if(cur < need) return 0;
        }
    }
    return cur >= need;
}

int main() {
    int a, b, k;
    int L, R, M, i;
    init();
    scanf("%d %d %d", &a, &b, &k);
    L = 0, R = b - a + 1;
    while(R - L > 1) {
        M = (L + R) / 2;
        if(good(a, b, M, k)) R = M;
        else L = M;
    }
    if(!good(a, b, R, k)) R = -1;
    printf("%d\n", R);
    return 0;
}

