use std::io;
use std::str;

pub struct Scanner<R> {
    reader: R,
    buffer: Vec<String>,
}

impl<R: io::BufRead> Scanner<R> {
    pub fn new(reader: R) -> Self {
        Self {
            reader,
            buffer: vec![],
        }
    }

    pub fn token<T: str::FromStr>(&mut self) -> T {
        loop {
            if let Some(token) = self.buffer.pop() {
                return token.parse().ok().expect("Failed parse");
            }
            let mut input = String::new();
            self.reader.read_line(&mut input).expect("Failed read");
            self.buffer = input.split_whitespace().rev().map(String::from).collect();
        }
    }
}

// Be careful for n = 10^6. In Codeforces, usize is a 32-bit integer.
fn sieve(n: i64) -> (Vec<i64>, Vec<bool>) {
    let mut is_prime = vec![true; (n as usize) + 1];
    is_prime[0] = false;
    is_prime[1] = false;
    let mut primes = Vec::new();
    for i in 2..=n {
        if is_prime[i as usize] {
            primes.push(i);
            let mut j = i * i;
            while j <= n {
                is_prime[j as usize] = false;
                j += i;
            }
        }
    }
    (primes, is_prime)
}

fn lower_bound(arr: &[i64], target: i64) -> usize {
    let mut lo = 0;
    let mut hi = arr.len();
    while lo < hi {
        let mid = lo + (hi - lo) / 2;
        if arr[mid] >= target {
            hi = mid;
        } else {
            lo = mid + 1;
        }
    }
    lo
}

fn count_primes(primes: &[i64], lo: i64, hi: i64) -> i64 {
    // How many primes are there in [lo, hi]?
    let lb_1 = lower_bound(primes, lo) as i64;
    let lb_2 = lower_bound(primes, hi + 1) as i64;
    lb_2 - lb_1
}

fn pred(a: i64, b: i64, k: i64, l: i64, primes: &[i64], is_prime: &[bool]) -> bool {
    // For ALL x in [a, b - l + 1], are there at least k prime numbers in [x, x + l - 1]?

    // window: [a, a + l - 1]
    let mut prime_count = count_primes(primes, a, a + l - 1);
    if prime_count < k {
        return false;
    }
    for x in (a + 1)..=(b - l + 1) {
    // for i in 1..(b - l - a + 2) {
    //     let x = a + i;
        // window: [x, x + l - 1]
        // previous window: [x - 1, x + l - 2]
        // if x - 1 was prime, remove it
        if is_prime[(x - 1) as usize] {
            prime_count -= 1;
        }

        // if x + l - 1 is prime, add it
        if is_prime[(x + l - 1) as usize] {
            prime_count += 1;
        }

        if prime_count < k {
            return false;
        }
    }
    true
}

fn search_l(a: i64, b: i64, k: i64, primes: &[i64], is_prime: &[bool]) -> i64 {
    let mut lo = 1;
    let mut hi = b - a + 2;
    while lo < hi {
        let mid = lo + (hi - lo) / 2;
        if pred(a, b, k, mid, primes, is_prime) {
            hi = mid;
        } else {
            lo = mid + 1;
        }
    }
    if lo == b - a + 2 {
        -1
    } else {
        lo
    }
}

fn solve<R: io::BufRead, W: io::Write>(scan: &mut Scanner<R>, out: &mut W) {
    let a: i64 = scan.token();
    let b: i64 = scan.token();
    let k: i64 = scan.token();

    let (primes, is_prime) = sieve(1000005);
    let ans = search_l(a, b, k, &primes, &is_prime);
    writeln!(out, "{}", ans).ok();
}

fn main() {
    let (stdin, stdout) = (io::stdin(), io::stdout());
    let mut scan = Scanner::new(stdin.lock());
    let mut out = io::BufWriter::new(stdout.lock());
    solve(&mut scan, &mut out);
}
